<?php require __DIR__.'/includes/bootstrap.php';$token=$_GET['token']??($_POST['token']??'');$s=db()->prepare('SELECT * FROM password_resets WHERE token_hash=? AND expires_at>NOW() AND used_at IS NULL LIMIT 1');$s->execute([hash('sha256',$token)]);$reset=$s->fetch();
if($_SERVER['REQUEST_METHOD']==='POST'&&$reset){verify_csrf();$p=$_POST['password']??'';if(strlen($p)>=12){db()->beginTransaction();db()->prepare('UPDATE users SET password_hash=? WHERE id=?')->execute([password_hash($p,PASSWORD_DEFAULT),$reset['user_id']]);db()->prepare('UPDATE password_resets SET used_at=NOW() WHERE id=?')->execute([$reset['id']]);db()->commit();flash('success','Password updated. Sign in with your new password.');redirect('login.php');}}
app_header('Reset Password');?><section class="auth-page"><form class="auth-card" method="post"><?=csrf_field()?><input type="hidden" name="token" value="<?=e($token)?>"><h1>Choose a new password</h1><?php if(!$reset):?><div class="alert error">This reset link is invalid or expired.</div><?php else:?><label>New password<input type="password" name="password" minlength="12" required></label><button class="button primary">Update Password</button><?php endif?></form></section><?php app_footer();
